function startPtzImagePoll() {
    if (_ptzImagePollInterval) return; // 已在运行
    
    _ptzImagePollInterval = setInterval(function() {
        if (!window.connectedDevice || !window.connectedDevice.ip) return;
        
        var dev = window.connectedDevice.ip;
        
        // 1. PTZ 坐标
        apiGet('/api/v1/ptz/' + dev + '/position').then(function(r) {
            if (r && r.success && r.data) {
                var posEl = document.getElementById('ptzPosition');
                if (posEl) {
                    posEl.innerHTML = 'Pan: ' + (r.data.pan || 0) + ' | Tilt: ' + (r.data.tilt || 0) + ' | Zoom: ' + (r.data.zoom || 0);
                }
            }
        }).catch(function(e) {});
        
        // 2. 白平衡 R/B
        apiGet('/api/v1/ptz/' + dev + '/image/whitebalance').then(function(r) {
            if (r && r.success && r.data) {
                var wb = r.data;
                var rEl = document.getElementById('ptzWbR');
                var bEl = document.getElementById('ptzWbB');
                if (rEl) rEl.textContent = 'R: ' + (wb.red_gain || '--');
                if (bEl) bEl.textContent = 'B: ' + (wb.blue_gain || '--');
            }
        }).catch(function(e) {});
        
        // 3. 降噪空域/时域 - v7.03: 显示实际数值（0 也显示 0）
        apiGet('/api/v1/ptz/' + dev + '/image/noisereduce').then(function(r) {
            if (r && r.success && r.data) {
                var nr = r.data;
                var sEl = document.getElementById('ptzDnrSpatial');
                var tEl = document.getElementById('ptzDnrTemporal');
                // v7.03: 显示实际数值
                var spatialVal = (nr.spatial_level !== undefined && nr.spatial_level !== null) ? nr.spatial_level : '--';
                var temporalVal = (nr.temporal_level !== undefined && nr.temporal_level !== null) ? nr.temporal_level : '--';
                if (sEl) sEl.textContent = '空域: ' + spatialVal;
                if (tEl) tEl.textContent = '时域: ' + temporalVal;
            }
        }).catch(function(e) {});
        
        // 4. 光圈
        apiGet('/api/v1/ptz/' + dev + '/image/iris').then(function(r) {
            if (r && r.success && r.data) {
                var ir = r.data;
                var iEl = document.getElementById('ptzIris');
                if (iEl) iEl.textContent = '光圈: ' + (ir.current_level || '--');
            }
        }).catch(function(e) {});
        
        // 5. 快门
        apiGet('/api/v1/ptz/' + dev + '/image/shutter').then(function(r) {
            if (r && r.success && r.data) {
                var sh = r.data;
                var sEl = document.getElementById('ptzShutter');
                if (sEl) sEl.textContent = '快门: ' + (sh.current_level || '--');
            }
        }).catch(function(e) {});
    }, 1000);
}

function stopPtzImagePoll() {
    if (_ptzImagePollInterval) {
        clearInterval(_ptzImagePollInterval);
        _ptzImagePollInterval = null;
    }
}

// 暴露到全局
window.startPtzImagePoll = startPtzImagePoll;
window.stopPtzImagePoll = stopPtzImagePoll;

// ==================== 暴露到全局 ====================
window.toggleSection = toggleSection;
window.loadDeviceImageParams = loadDeviceImageParams;
window.setSharpness = setSharpness;
window.setWhiteBalanceMode = setWhiteBalanceMode;
window.setWhiteBalanceGain = setWhiteBalanceGain;
window.setNoiseReduce = setNoiseReduce;
window.setShutterSpeed = setShutterSpeed;
window.setIris = setIris;
window.setExposureMode = setExposureMode;
window.togglePtzOsd = togglePtzOsd;
window.toggleInfoOsd = toggleInfoOsd;
window.updatePtzOsdButtons = updatePtzOsdButtons;
window.updateInfoOsdButtons = updateInfoOsdButtons;
// v7.32: 新增功能检测相关函数
window.goToFunctionTest = goToFunctionTest;
window.showFunctionOverlay = showFunctionOverlay;
window.removeFunctionOverlay = removeFunctionOverlay;
</script>

