#!/usr/bin/env python
# -*- coding: utf-8 -*-
"""研究海康官方web管理端的码流切换实现"""

from playwright.sync_api import sync_playwright
import time
import json

with sync_playwright() as p:
    browser = p.chromium.launch(headless=True)
    page = browser.new_page(viewport={'width': 1920, 'height': 1080})

    # 打开海康web管理端
    print('1. 打开海康web管理端...')
    page.goto('http://192.168.5.72', timeout=30000)
    time.sleep(3)
    page.screenshot(path='test_results/hik_01_login.png')

    # 登录
    print('2. 登录...')
    # 尝试多种选择器
    for sel in ['input[name="username"]', '#username', 'input[type="text"]']:
        try:
            page.fill(sel, 'admin')
            print(f'  用户名填充成功: {sel}')
            break
        except:
            pass

    for sel in ['input[name="password"]', '#password', 'input[type="password"]']:
        try:
            page.fill(sel, 'Nftw1357')
            print(f'  密码填充成功: {sel}')
            break
        except:
            pass

    for sel in ['button[type="submit"]', 'input[type="submit"]', 'button:has-text("Login")', 'button:has-text("登录")', '.login-btn']:
        try:
            page.click(sel, timeout=3000)
            print(f'  登录按钮点击成功: {sel}')
            break
        except:
            pass

    time.sleep(5)
    page.screenshot(path='test_results/hik_02_after_login.png')
    print(f'  当前URL: {page.url}')

    # 查找预览入口
    print('3. 查找预览入口...')
    for sel in ['text=预览', 'text=Live', 'text=Preview', '[data-page="preview"]', '.menu-item:has-text("预览")']:
        try:
            page.click(sel, timeout=3000)
            print(f'  找到并点击: {sel}')
            break
        except:
            pass

    time.sleep(3)
    page.screenshot(path='test_results/hik_03_preview.png')
    print(f'  当前URL: {page.url}')

    # 获取页面中所有script标签的内容
    print('4. 分析页面JavaScript...')

    # 查找码流切换相关的元素和函数
    stream_info = page.evaluate('''() => {
        const result = {
            streamButtons: [],
            streamSelects: [],
            iStreamType: [],
            webVideoCtrlMethods: [],
            wsConnections: [],
        };

        // 查找码流切换按钮
        document.querySelectorAll('button, select, a, div').forEach(el => {
            const text = el.textContent || '';
            const id = el.id || '';
            const cls = el.className || '';
            if (text.includes('码流') || text.includes('主码流') || text.includes('子码流') || 
                text.includes('Stream') || id.includes('stream') || cls.includes('stream')) {
                result.streamButtons.push({
                    tag: el.tagName,
                    id: id,
                    class: cls,
                    text: text.substring(0, 50),
                    onclick: el.getAttribute('onclick') || '',
                });
            }
        });

        // 查找select元素
        document.querySelectorAll('select').forEach(el => {
            const options = [];
            el.querySelectorAll('option').forEach(opt => {
                options.push({value: opt.value, text: opt.textContent});
            });
            if (el.id.includes('stream') || el.id.includes('Stream') || 
                options.some(o => o.text.includes('码流') || o.text.includes('Stream'))) {
                result.streamSelects.push({
                    id: el.id,
                    name: el.name,
                    options: options,
                });
            }
        });

        // 检查WebVideoCtrl对象
        if (typeof WebVideoCtrl !== 'undefined') {
            result.webVideoCtrlMethods = Object.getOwnPropertyNames(WebVideoCtrl).filter(
                m => m.startsWith('I_') || m.includes('Stream') || m.includes('stream')
            );
        }

        // 检查全局变量
        for (const key of Object.keys(window)) {
            if (key.includes('Stream') || key.includes('stream') || key.includes('iStream')) {
                result.iStreamType.push({key: key, value: String(window[key])});
            }
        }

        return result;
    }''')

    print('  码流相关按钮:', json.dumps(stream_info.get('streamButtons', []), ensure_ascii=False, indent=2))
    print('  码流相关选择框:', json.dumps(stream_info.get('streamSelects', []), ensure_ascii=False, indent=2))
    print('  WebVideoCtrl方法:', stream_info.get('webVideoCtrlMethods', []))
    print('  全局变量:', json.dumps(stream_info.get('iStreamType', []), ensure_ascii=False, indent=2))

    # 分析changeStreamType函数的实现
    print('5. 分析changeStreamType函数...')
    func_info = page.evaluate('''() => {
        const result = {};

        // 检查changeStreamType函数
        if (typeof changeStreamType === 'function') {
            result.changeStreamType = changeStreamType.toString().substring(0, 500);
        }

        // 检查clickStartRealPlay函数
        if (typeof clickStartRealPlay === 'function') {
            result.clickStartRealPlay = clickStartRealPlay.toString().substring(0, 500);
        }

        return result;
    }''')

    print('  changeStreamType:', func_info.get('changeStreamType', 'not found'))
    print('  clickStartRealPlay:', func_info.get('clickStartRealPlay', 'not found'))

    browser.close()
    print('\n分析完成！')

