arguments.command:
cd astrohub && Write-Output "=== 检查 src 目录中是否有版本信息 ==="
Get-ChildItem src -Recurse -Include "*.py" | ForEach-Object { 
    $content = Get-Content $_.FullName -Raw -ErrorAction SilentlyContinue
    if ($content -match "VERSION.*6\.") {
        Write-Output "$($_.Name): $([regex]::Match($content, 'VERSION.*6\.[0-9]+').Value)"
    }
}

cd astrohub && Write-Output "=== 搜索所有包含 VERSION 6.x 的文件 ==="
Get-ChildItem -Recurse -Include *.py, *.js, *.html | ForEach-Object {
    $content = Get-Content $_.FullName -Raw -ErrorAction SilentlyContinue
    if ($content -match 'VERSION.*"v?6\.') {
        Write-Output "$($_.FullName)"
    }
} | Select-Object -First 20

cd astrohub && Write-Output "=== 搜索 backup 目录中的版本信息 ==="
Get-ChildItem backup_* -Directory | ForEach-Object {
    $verFile = Join-Path $_.FullName "main/constants.py"
    if (Test-Path $verFile) {
        $ver = Get-Content $verFile | Select-String "VERSION"
        Write-Output "$($_.Name): $ver"
    } else {
        $verFile2 = Join-Path $_.FullName "src/main/constants.py"
        if (Test-Path $verFile2) {
            $ver = Get-Content $verFile2 | Select-String "VERSION"
            Write-Output "$($_.Name): $ver"
        }
    }
}

cd astrohub && Write-Output "=== 列出所有备份目录的完整内容 ==="
Get-ChildItem backup_* -Directory | ForEach-Object {
    Write-Output "`n=== $($_.Name) ==="
    Get-ChildItem $_.FullName -Recurse -Include constants.py | ForEach-Object {
        $ver = Get-Content $_ | Select-String "VERSION" | Select-Object -First 1
        Write-Output "  $($_.FullName): $ver"
    }
}

cd astrohub && Write-Output "=== 检查所有 .json 配置文件中是否有版本信息 ==="
Get-ChildItem -Recurse -Include *.json | ForEach-Object {
    $content = Get-Content $_.FullName -Raw -ErrorAction SilentlyContinue
    if ($content -match '"version".*:.*"6\.') {
        Write-Output "$($_.FullName)"
    }
} | Select-Object -First 10

cd astrohub && Write-Output "=== 检查 README 或 CHANGELOG ==="
Get-ChildItem -Include README*, CHANGELOG*, HISTORY* -File | ForEach-Object {
    Write-Output "`n=== $($_.Name) ==="
    Get-Content $_.FullName | Select-Object -First 30
}

cd astrohub && Write-Output "=== 完整备份列表 ==="
$backups = Get-ChildItem -Directory | Where-Object { $_.Name -like "backup*" }
foreach ($b in $backups) {
    Write-Output $b.Name
}

$dirs = Get-ChildItem astrohub -Directory -ErrorAction SilentlyContinue
Write-Output "Total directories: $($dirs.Count)"
$dirs | Where-Object { $_.Name -like "backup*" } | ForEach-Object { Write-Output $_.Name }
